oldWay:
h1 { font-size: 1.25rem; }

@media (min-width: 480px) {
  h1 { font-size: 1.5rem; }
}

@media (min-width: 768px) {
  h1 { font-size: 2rem; }
}

@media (min-width: 1024px) {
  h1 { font-size: 2.5rem; }
}

modernWay:
h1 {
  /* clamp(minimum, preferred, maximum) */
  font-size: clamp(1.25rem, 5vw, 2.5rem);
}

